mapper.select:
select log_id, park_id, project_id, flow_id, node_name, node_type, action_type, operator_name, opinion, result_status, transfer_to, cc_users, attachment_url, operate_time, create_by, create_time from biz_approval_log
and park_id = #{log.parkId} and project_id = #{log.projectId} and flow_id = #{log.flowId} and action_type = #{log.actionType} and operator_name = #{log.operatorName}
order by operate_time asc, log_id asc

mapper.insert:
insert into biz_approval_log (
	park_id, project_id, flow_id, node_name, node_type, action_type, operator_name,
	opinion, result_status, transfer_to, cc_users, attachment_url, operate_time, create_by, create_time
) values (
	#{parkId}, #{projectId}, #{flowId}, #{nodeName}, #{nodeType}, #{actionType}, #{operatorName},
	#{opinion}, #{resultStatus}, #{transferTo}, #{ccUsers}, #{attachmentUrl}, #{operateTime}, #{createBy}, #{createTime}
)
